from collections import defaultdict, deque

class Solution(object):
    def shortestDistanceAfterQueries(self, n, queries):
        adj = defaultdict(list)
        for i in range(n - 1):
            adj[i].append(i + 1)

        def bfs():
            dist = [-1] * n
            dist[0] = 0
            q = deque([0])
            while q:
                node = q.popleft()
                for nb in adj[node]:
                    if dist[nb] == -1:
                        dist[nb] = dist[node] + 1
                        if nb == n - 1:
                            return dist[nb]
                        q.append(nb)
            return dist[n - 1]

        ans = []
        for u, v in queries:
            adj[u].append(v)
            ans.append(bfs())
        return ans
